#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin >> T;
    while(T--){
        int N;
        cin >> N;
        vector<long long> h(N);
        for(int i = 0; i < N; i++){
            cin >> h[i];
        }

        vector<long long> leftMax(N), rightMax(N);
        leftMax[0] = h[0];
        for(int i = 1; i < N; i++){
            leftMax[i] = max(leftMax[i - 1], h[i]);
        }

        rightMax[N - 1] = h[N - 1];
        for(int i = N - 2; i >= 0; i--){
            rightMax[i] = max(rightMax[i + 1], h[i]);
        }

        vector<long long> water(N, 0);
        for(int i = 0; i < N; i++){
            long long minHeight = min(leftMax[i], rightMax[i]);
            if(minHeight > h[i])
                water[i] = minHeight - h[i];
            else
                water[i] = 0;
        }

        long long maxSection = 0, currentSection = 0;
        for(int i = 0; i < N; i++){
            if(water[i] > 0)
                currentSection += water[i];
            else {
                maxSection = max(maxSection, currentSection);
                currentSection = 0;
            }
        }
        maxSection = max(maxSection, currentSection);

        cout << maxSection << "\n";
    }
    return 0;
}

