import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.IOException;
import java.util.StringTokenizer;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        int t = Integer.parseInt(reader.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while(t-- > 0) {
            int n = Integer.parseInt(reader.readLine().trim());
            int[] heights = new int[n];
            StringTokenizer st = new StringTokenizer(reader.readLine());
            for (int i = 0; i < n; i++) {
                heights[i] = Integer.parseInt(st.nextToken());
            }

            int[] leftMax = new int[n];
            int[] rightMax = new int[n];

            leftMax[0] = heights[0];
            for (int i = 1; i < n; i++) {
                leftMax[i] = Math.max(leftMax[i-1], heights[i]);
            }

            rightMax[n-1] = heights[n-1];
            for (int i = n-2; i >= 0; i--) {
                rightMax[i] = Math.max(rightMax[i+1], heights[i]);
            }

            // Compute water trapped at each position
            int[] water = new int[n];
            for (int i = 0; i < n; i++) {
                int trapped = Math.min(leftMax[i], rightMax[i]) - heights[i];
                water[i] = (trapped > 0) ? trapped : 0;
            }

            // Find maximum sum of contiguous positive water cells (one section)
            long maxSection = 0;
            long currentSum = 0;
            for (int i = 0; i < n; i++) {
                if(water[i] > 0) {
                    currentSum += water[i];
                } else {
                    if(currentSum > maxSection) {
                        maxSection = currentSum;
                    }
                    currentSum = 0;
                }
            }
            if(currentSum > maxSection) {
                maxSection = currentSum;
            }

            sb.append(maxSection).append("\n");
        }
        System.out.print(sb);
    }
}

