function maxWaterInSection(n, heights) {
    // Compute left max array
    let leftMax = new Array(n);
    leftMax[0] = heights[0];
    for (let i = 1; i < n; i++) {
        leftMax[i] = Math.max(leftMax[i - 1], heights[i]);
    }
    // Compute right max array
    let rightMax = new Array(n);
    rightMax[n - 1] = heights[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        rightMax[i] = Math.max(rightMax[i + 1], heights[i]);
    }
    // Calculate water trapped at each index
    let water = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        let waterLevel = Math.min(leftMax[i], rightMax[i]);
        if (waterLevel > heights[i]) {
            water[i] = waterLevel - heights[i];
        }
    }
    // Find maximum contiguous section sum of water
    let maxSection = 0, currentSection = 0;
    for (let i = 0; i < n; i++) {
        if (water[i] > 0) {
            currentSection += water[i];
        } else {
            maxSection = Math.max(maxSection, currentSection);
            currentSection = 0;
        }
    }
    maxSection = Math.max(maxSection, currentSection);
    return maxSection;
}
